CREATE VIEW `ads_grant_user_center_reward_view` (`dt` COMMENT "createtime 分区", `product_id` COMMENT "产品id", `id` COMMENT "自增id", `user_id` COMMENT "UserId", `sign_id` COMMENT "签到模块id", `sign_name` COMMENT "签到模块名", `use_type` COMMENT "应用场景（0活动，1福利中心)", `days` COMMENT "签到天数", `type` COMMENT "签到类型 1:签到 2:补签", `reward_id` COMMENT "商品id", `award_type` COMMENT "商品类型0积分，1阅读背景，2头像框，3礼券，4限时免费卡,5抽奖次数", `send_num` COMMENT "数量", `send_id` COMMENT "SendId", `sign_date` COMMENT "签到时间", `source_key` COMMENT "来源key", `is_special_reward` COMMENT "否是大奖", `create_time` COMMENT "创建时间", `app_id` COMMENT "应用程序id", `etl_time` COMMENT "处理时间")
COMMENT "福利中心-用户阶梯奖励日志" AS SELECT `dwd`.`dwd_grant_user_center_reward`.`dt`, `dwd`.`dwd_grant_user_center_reward`.`product_id`, `dwd`.`dwd_grant_user_center_reward`.`id`, `dwd`.`dwd_grant_user_center_reward`.`user_id`, `dwd`.`dwd_grant_user_center_reward`.`sign_id`, `dwd`.`dwd_grant_user_center_reward`.`sign_name`, `dwd`.`dwd_grant_user_center_reward`.`use_type`, `dwd`.`dwd_grant_user_center_reward`.`days`, `dwd`.`dwd_grant_user_center_reward`.`type`, `dwd`.`dwd_grant_user_center_reward`.`reward_id`, `dwd`.`dwd_grant_user_center_reward`.`award_type`, `dwd`.`dwd_grant_user_center_reward`.`send_num`, `dwd`.`dwd_grant_user_center_reward`.`send_id`, `dwd`.`dwd_grant_user_center_reward`.`sign_date`, `dwd`.`dwd_grant_user_center_reward`.`source_key`, `dwd`.`dwd_grant_user_center_reward`.`is_special_reward`, `dwd`.`dwd_grant_user_center_reward`.`create_time`, `dwd`.`dwd_grant_user_center_reward`.`app_id`, `dwd`.`dwd_grant_user_center_reward`.`etl_time`
FROM `dwd`.`dwd_grant_user_center_reward`;